  ('elementary-10ced7e2-moex-00802', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '有關公務人員培訓措施，最接近下列何種人力資源的功能？', '["紀律管理", "工作分析", "員額評鑑", "組織發展"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "a9ea86dba62c", "answer_pdf_sha1": "dfbc0bd4bafe", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00803', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '公務人員之俸給係依「公務人員俸給法」行之，下列敘述何者錯誤？', '["公務人員之俸給，分本俸（年功俸）及加給", "本俸係指各職等人員依法應領取之基本給與", "年功俸係指各職等高於本俸最高俸級之給與", "加給係指本俸、年功俸以外，因所任職務種類、性質與教育程度之不同，而另加之給與"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "a9ea86dba62c", "answer_pdf_sha1": "dfbc0bd4bafe", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00804', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '關於公務人員訓練的各種評鑑方法，下列何者最能展現公務人員受訓的成果？', '["受訓時的考試與作業成績", "受訓者的滿意度調查", "受訓後在工作崗位上的表現", "受訓者當年度的受訓時數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "a9ea86dba62c", "answer_pdf_sha1": "dfbc0bd4bafe", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00805', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '某甲是一位經常需要跑外勤的人員。當他在外工作時，主管無法直接觀察到他的實際表現；但是當他在 辦公室工作時，主管都能感受到他的工作熱情與良好的工作表現。主管依照他內勤工作的表現，判斷他 外勤工作表現一定也同樣良好。請問某甲的主管在打考績時最可能犯了什麼謬誤？', '["沒有犯錯", "趨中的謬誤", "暈輪謬誤", "過寬或過嚴的謬誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "a9ea86dba62c", "answer_pdf_sha1": "dfbc0bd4bafe", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
