  ('elementary-10ced7e2-moex-00807', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '各機關學校選送國外進修之公務人員，其進修期間，下列敘述何者錯誤？', '["經中央一級機關專案核定國外進修人員，其進修期限最長為四年", "專題研究期間為六個月以內。必要時，得依規定申請延長，延長期間最長為三個月", "入學進修期間為一年以內。但經各主管機關核准延長者，延長期間最長為一年", "選修學分期間為六個月以內。但經各主管機關核准延長者，延長期間最長為一年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "a9ea86dba62c", "answer_pdf_sha1": "dfbc0bd4bafe", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
