  ('elementary-10ced7e2-moex-00809', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '有關初任各官等職務之人員，其等級起敘之敘述，下列何者錯誤？', '["高等考試之二級考試及格者，初任薦任職務時，敘薦任第九職等本俸一級", "普通考試及格者，敘委任第三職等本俸一級", "初等考試及格者，敘委任第一職等本俸一級", "高等考試之三級考試及格者，初任薦任職務時，敘薦任第六職等本俸一級"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "a9ea86dba62c", "answer_pdf_sha1": "dfbc0bd4bafe", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
